6	//! Stream scheduling policies that control how [`DeviceOperation`]s are
7	//! assigned to CUDA streams.
8	//!
9	//! A [`SchedulingPolicy`] decouples operation construction from stream
10	//! selection. The policy chooses a stream when an operation is scheduled or
11	//! executed synchronously, enabling transparent overlap of independent work.
12	//!
13	//! | Policy                   | Behaviour                                    |
14	//! |--------------------------|----------------------------------------------|
15	//! | [`StreamPoolRoundRobin`] | Rotates across *N* streams for HW overlap    |
16	//! | [`SingleStream`]         | Serialises all work onto one stream          |
17	//!
18	//! [`DeviceOperation`]: crate::device_operation::DeviceOperation
19	
20	use crate::device_future::DeviceFuture;
21	use crate::device_operation::{DeviceOperation, ExecutionContext};
22	use crate::error::{DeviceError, device_error};
23	use cuda_core::{CudaContext, CudaStream};
24	use std::sync::Arc;
25	use std::sync::atomic::AtomicUsize;
26	
27	/// Top-level enum wrapping all supported scheduling policy implementations.
28	///
29	/// Used as the concrete policy type stored in
30	/// [`AsyncDeviceContext`](crate::device_context::AsyncDeviceContext).
31	pub enum GlobalSchedulingPolicy {
32	    /// Round-robin across a pool of CUDA streams.
33	    RoundRobin(StreamPoolRoundRobin),
34	}
35	
36	impl GlobalSchedulingPolicy {
37	    /// Returns a reference to the inner policy as a trait object.
38	    pub fn as_scheduling_policy(&self) -> Result<&impl SchedulingPolicy, DeviceError> {
39	        match self {
40	            GlobalSchedulingPolicy::RoundRobin(rr) => Ok(rr),
41	        }
42	    }
43	}
44	
45	/// Delegates to the inner policy variant.
46	impl SchedulingPolicy for GlobalSchedulingPolicy {
47	    fn init(&mut self, ctx: &Arc<CudaContext>) -> Result<(), DeviceError> {
48	        match self {
49	            GlobalSchedulingPolicy::RoundRobin(rr) => rr.init(ctx),
50	        }
51	    }
52	    fn schedule<T: Send, O: DeviceOperation<Output = T>>(
53	        &self,
54	        op: O,
55	    ) -> Result<DeviceFuture<T, O>, DeviceError> {
56	        match self {
57	            GlobalSchedulingPolicy::RoundRobin(rr) => rr.schedule(op),
58	        }
59	    }
60	    fn sync<T: Send, O: DeviceOperation<Output = T>>(&self, op: O) -> Result<T, DeviceError> {
61	        match self {
62	            GlobalSchedulingPolicy::RoundRobin(rr) => rr.sync(op),
63	        }
64	    }
65	}
66	
67	/// `Arc`-wrapped policy delegates scheduling but rejects re-initialization,
68	/// since the inner data cannot be mutated through an `Arc`.
69	impl SchedulingPolicy for Arc<GlobalSchedulingPolicy> {
70	    fn init(&mut self, _ctx: &Arc<CudaContext>) -> Result<(), DeviceError> {
71	        Err(DeviceError::Scheduling(
72	            "Cannot initialize scheduling policy inside an Arc.".to_string(),
73	        ))
74	    }
75	    fn schedule<T: Send, O: DeviceOperation<Output = T>>(
76	        &self,
77	        op: O,
78	    ) -> Result<DeviceFuture<T, O>, DeviceError> {
79	        match self.as_ref() {
80	            GlobalSchedulingPolicy::RoundRobin(rr) => rr.schedule(op),
81	        }
82	    }
83	    fn sync<T: Send, O: DeviceOperation<Output = T>>(&self, op: O) -> Result<T, DeviceError> {
84	        match self.as_ref() {
85	            GlobalSchedulingPolicy::RoundRobin(rr) => rr.sync(op),
86	        }
87	    }
88	}
89	
90	/// Strategy for assigning [`DeviceOperation`]s to CUDA streams.
91	///
92	/// Implementations must be `Sync` because the policy is shared across all
93	/// operations on a device context.
94	///
95	/// [`DeviceOperation`]: crate::device_operation::DeviceOperation
96	pub trait SchedulingPolicy: Sync {
97	    /// One-time initialization with the CUDA context (creates streams, etc.).
98	    fn init(&mut self, ctx: &Arc<CudaContext>) -> Result<(), DeviceError>;
99	
100	    /// Assigns a stream to `op` and returns a [`DeviceFuture`] ready to be
101	    /// polled.
102	    fn schedule<T: Send, O: DeviceOperation<Output = T>>(
103	        &self,
104	        op: O,
105	    ) -> Result<DeviceFuture<T, O>, DeviceError>;
106	
107	    /// Executes `op` synchronously on a policy-chosen stream and blocks until
108	    /// the stream is idle.
109	    fn sync<T: Send, O: DeviceOperation<Output = T>>(&self, op: O) -> Result<T, DeviceError>;
110	}
111	
112	/// Round-robin scheduler over a fixed-size pool of CUDA streams.
113	///
114	/// Each call to [`schedule`](SchedulingPolicy::schedule) or
115	/// [`sync`](SchedulingPolicy::sync) atomically advances the stream index,
116	/// distributing work across streams to enable hardware-level overlap of
117	/// independent kernels and memory transfers.
118	#[derive(Debug)]
119	pub struct StreamPoolRoundRobin {
120	    /// Device ordinal this pool belongs to.
121	    device_id: usize,
122	    /// Monotonically increasing counter; wrapped with `% num_streams`.
123	    next_stream_idx: AtomicUsize,
124	    /// Number of streams in the pool.
125	    pub(crate) num_streams: usize,
126	    /// `None` until [`init`](SchedulingPolicy::init) is called.
127	    pub(crate) stream_pool: Option<Vec<Arc<CudaStream>>>,
128	}
129	
130	impl StreamPoolRoundRobin {
131	    /// Creates an un-initialized round-robin policy for `device_id` with
132	    /// `num_streams` streams.
133	    ///
134	    /// # Safety
135	    ///
136	    /// The caller must call [`SchedulingPolicy::init`] before scheduling any
137	    /// operations. Using the policy before initialization produces an error.
138	    pub unsafe fn new(device_id: usize, num_streams: usize) -> Self {
139	        Self {
140	            device_id,
141	            num_streams,
142	            stream_pool: None,
143	            next_stream_idx: AtomicUsize::new(0),
144	        }
145	    }
146	}
147	
148	impl SchedulingPolicy for StreamPoolRoundRobin {
149	    /// Allocates `num_streams` CUDA streams on the provided context.
150	    fn init(&mut self, ctx: &Arc<CudaContext>) -> Result<(), DeviceError> {
151	        let mut pool = vec![];
152	        for _ in 0..self.num_streams {
153	            pool.push(ctx.new_stream()?);
154	        }
155	        self.stream_pool = Some(pool);
156	        Ok(())
157	    }
158	
159	    /// Picks the next stream (round-robin), executes `op`, and synchronizes.
160	    fn sync<T: Send, O: DeviceOperation<Output = T>>(&self, op: O) -> Result<T, DeviceError> {
161	        let idx = self
162	            .next_stream_idx
163	            .fetch_add(1, std::sync::atomic::Ordering::Relaxed)
164	            % self.num_streams;
165	        let pool = self
166	            .stream_pool
167	            .as_ref()
168	            .ok_or_else(|| device_error(self.device_id, "Stream pool not initialized."))?;
169	        op.sync_on(&pool[idx])
170	    }
171	
172	    /// Picks the next stream (round-robin) and wraps `op` in a
173	    /// [`DeviceFuture`].
174	    fn schedule<T: Send, O: DeviceOperation<Output = T>>(
175	        &self,
176	        op: O,
177	    ) -> Result<DeviceFuture<T, O>, DeviceError> {
178	        let idx = self
179	            .next_stream_idx
180	            .fetch_add(1, std::sync::atomic::Ordering::Relaxed)
181	            % self.num_streams;
182	        let pool = self
183	            .stream_pool
184	            .as_ref()
185	            .ok_or_else(|| device_error(self.device_id, "Stream pool not initialized."))?;
186	        // `DeviceFuture` implements `Drop`, so functional-update syntax
187	        // (`..Default::default()`) would move fields out of a droppable
188	        // value (E0509). Spell every field out instead.
189	        Ok(DeviceFuture {
190	            device_operation: Some(op),
191	            execution_context: Some(ExecutionContext::new(Arc::clone(&pool[idx]))),
192	            result: None,
193	            error: None,
194	            state: Default::default(),
195	            callback_state: None,
196	        })
197	    }
198	}
199	
200	/// Single-stream scheduler that serialises all work onto one CUDA stream.
201	///
202	/// Useful for debugging or when ordering guarantees are required between
203	/// all operations on a device.
204	#[derive(Debug)]
205	pub struct SingleStream {
206	    /// The single stream. `None` until [`init`](SchedulingPolicy::init).
207	    pub stream: Option<Arc<CudaStream>>,
208	}
209	
210	impl SingleStream {
211	    /// Creates an un-initialized single-stream policy.
212	    ///
213	    /// # Safety
214	    ///
215	    /// The caller must call [`SchedulingPolicy::init`] before use.
216	    pub unsafe fn new() -> Self {
217	        Self { stream: None }
218	    }
219	}
220	
221	impl SchedulingPolicy for SingleStream {
222	    /// Allocates one CUDA stream on `ctx`.
223	    fn init(&mut self, ctx: &Arc<CudaContext>) -> Result<(), DeviceError> {
224	        self.stream = Some(ctx.new_stream()?);
225	        Ok(())
226	    }
227	
228	    /// Wraps `op` in a [`DeviceFuture`] bound to the single stream.
229	    fn schedule<T: Send, O: DeviceOperation<Output = T>>(
230	        &self,
231	        op: O,
232	    ) -> Result<DeviceFuture<T, O>, DeviceError> {
233	        let stream = self.stream.as_ref().unwrap();
234	        // See `StreamPoolRoundRobin::schedule` for why the fields are
235	        // spelled out instead of using `..Default::default()`.
236	        Ok(DeviceFuture {
237	            device_operation: Some(op),
238	            execution_context: Some(ExecutionContext::new(Arc::clone(stream))),
239	            result: None,
240	            error: None,
241	            state: Default::default(),
242	            callback_state: None,
243	        })
244	    }
245	
246	    /// Executes `op` synchronously on the single stream.
247	    fn sync<T: Send, O: DeviceOperation<Output = T>>(&self, op: O) -> Result<T, DeviceError> {
248	        let stream = self.stream.as_ref().unwrap();
249	        op.sync_on(stream)
250	    }
251	}
