1	/*
2	 * SPDX-FileCopyrightText: Copyright (c) 2026 NVIDIA CORPORATION & AFFILIATES. All rights reserved.
3	 * SPDX-License-Identifier: Apache-2.0
4	 */
5	
6	//! Deferred reclamation of results cancelled while GPU work is in flight.
7	//!
8	//! Cancelling a [`DeviceFuture`] cannot cancel GPU work that has already
9	//! been submitted: kernels run to completion regardless of what the host
10	//! does. What cancellation *can* do is decide when the host releases the
11	//! resources the kernel is still using. Dropping them immediately is
12	//! unsound (the stream-ordered allocator may hand the memory to the next
13	//! allocation while the kernel still writes to it), and synchronizing the
14	//! stream inside `Drop` blocks executor threads for an unbounded time.
15	//!
16	//! Instead, cancelled in-flight results are *parked* here together with a
17	//! completion gate (a CUDA event recorded on the assigned stream after the
18	//! submitted work):
19	//!
20	//! ```text
21	//! drop(future)                 later sweep (poll / drop / drain)
22	//!   record event on stream       event passed?  -> drop the result
23	//!   park (event, result)         still running? -> keep it parked
24	//! ```
25	//!
26	//! Parked results are swept opportunistically on subsequent future polls
27	//! and drops, or deterministically via [`drain`]. Payloads are never
28	//! dropped inside a CUDA host callback (callbacks must not call CUDA APIs,
29	//! and dropping a device buffer enqueues an async free), and a sweep never
30	//! blocks on GPU progress.
31	//!
32	//! Entries that are still parked at process exit are leaked; the driver
33	//! reclaims device memory at process teardown, while dropping them early
34	//! could corrupt memory that is still in use.
35	//!
36	//! [`DeviceFuture`]: crate::device_future::DeviceFuture
37	
38	use cuda_core::{CudaEvent, DriverError};
39	use std::io::{self, Write};
40	use std::mem;
41	use std::sync::atomic::{AtomicUsize, Ordering};
42	use std::sync::{Mutex, MutexGuard};
43	
44	/// Completion gate guarding a parked result.
45	///
46	/// Production code uses a [`CudaEvent`] recorded on the stream that runs
47	/// the cancelled work. Tests substitute host-side mocks.
48	pub(crate) trait ReclaimGate: Send {
49	    /// Returns `true` when the device timeline has passed the gate.
50	    /// Must never block.
51	    fn passed(&self) -> Result<bool, DriverError>;
52	
53	    /// Blocks until the device timeline has passed the gate.
54	    fn wait(&self) -> Result<(), DriverError>;
55	}
56	
57	impl ReclaimGate for CudaEvent {
58	    fn passed(&self) -> Result<bool, DriverError> {
59	        self.query()
60	    }
61	
62	    fn wait(&self) -> Result<(), DriverError> {
63	        self.synchronize()
64	    }
65	}
66	
67	/// A parked result and the gate that decides when it may be dropped.
68	struct LimboEntry {
69	    /// Completion gate; the payload may only drop after it has passed.
70	    gate: Box<dyn ReclaimGate>,
71	    /// Type-erased result kept alive on behalf of the cancelled future.
72	    payload: Box<dyn Send>,
73	}
74	
75	/// Number of parked entries. Mirrors `LIMBO.len()`; updated only while the
76	/// limbo lock is held, read lock-free as the sweep fast path.
77	static PENDING: AtomicUsize = AtomicUsize::new(0);
78	
79	/// All currently parked entries, across every device and thread.
80	static LIMBO: Mutex<Vec<LimboEntry>> = Mutex::new(Vec::new());
81	
82	/// Locks the limbo list, recovering from poisoning.
83	///
84	/// A poisoned lock only means another thread panicked while holding it;
85	/// the list itself stays consistent because payloads are always dropped
86	/// outside the lock.
87	fn limbo() -> MutexGuard<'static, Vec<LimboEntry>> {
88	    LIMBO
89	        .lock()
90	        .unwrap_or_else(|poisoned| poisoned.into_inner())
91	}
92	
93	/// Parks `payload` until `gate` reports completion.
94	pub(crate) fn park(gate: impl ReclaimGate + 'static, payload: Box<dyn Send>) {
95	    let mut entries = limbo();
96	    entries.push(LimboEntry {
97	        gate: Box::new(gate),
98	        payload,
99	    });
100	    PENDING.store(entries.len(), Ordering::Release);
101	}
102	
103	/// Number of results currently parked awaiting reclamation.
104	pub fn pending() -> usize {
105	    PENDING.load(Ordering::Acquire)
106	}
107	
108	/// Drops every parked result whose gate has passed. Never blocks on GPU
109	/// progress. Returns the number of results reclaimed.
110	///
111	/// Called automatically on every [`DeviceFuture`] poll and drop; safe to
112	/// call manually at any time.
113	///
114	/// [`DeviceFuture`]: crate::device_future::DeviceFuture
115	pub fn sweep() -> usize {
116	    if PENDING.load(Ordering::Acquire) == 0 {
117	        return 0;
118	    }
119	    let completed: Vec<LimboEntry> = {
120	        let mut entries = limbo();
121	        let mut kept = Vec::with_capacity(entries.len());
122	        let mut done = Vec::new();
123	        for entry in entries.drain(..) {
124	            match entry.gate.passed() {
125	                Ok(true) => done.push(entry),
126	                // Still in flight, or the query failed. Dropping early
127	                // would release memory the device may still be using, so
128	                // the entry stays parked.
129	                Ok(false) | Err(_) => kept.push(entry),
130	            }
131	        }
132	        *entries = kept;
133	        PENDING.store(entries.len(), Ordering::Release);
134	        done
135	    };
136	    // Dropped outside the lock: a payload's own drop may park or sweep.
137	    let reclaimed = completed.len();
138	    drop(completed);
139	    reclaimed
140	}
141	
142	/// Blocking drain: waits for every parked gate to pass, then drops the
143	/// payload. Returns the number of results reclaimed.
144	///
145	/// When even the blocking wait fails, the payload is deliberately leaked
146	/// with a message on stderr: if the driver cannot prove the GPU work
147	/// finished, leaking is safer than freeing memory the device may still
148	/// write to.
149	///
150	/// Call this before tearing down a process or test when deterministic
151	/// reclamation is required. It must not be called from a CUDA host
152	/// callback or while holding a thread-local device-context borrow.
153	pub fn drain() -> usize {
