6	#![allow(clippy::too_many_arguments, clippy::type_complexity)]
7	
8	//! Async MLP Pipeline Example
9	//!
10	//! Demonstrates the full `cuda-async` execution model with a multi-kernel
11	//! forward pass: GEMM → MatVec → ReLU, run concurrently across multiple
12	//! simulated devices.
13	//!
14	//! # Async patterns showcased
15	//!
16	//! - `with_context`         — stream-aware memory operations as DeviceOperations
17	//! - `and_then`             — chaining dependent kernel launches on the same stream
18	//! - `zip!`                 — combining independent allocations into one operation
19	//! - `.arc()`               — sharing weights across batches via Arc
20	//! - `tokio::spawn`         — concurrent batch execution across the stream pool
21	//! - `.await`               — non-blocking completion
22	//! - `value()`              — lifting host data into the DeviceOperation graph
23	//!
24	//! # Pipeline
25	//!
26	//! ```text
27	//! For each batch:
28	//!   input [DIM×DIM] ──► GEMM(input, W0) ──► hidden [DIM×DIM]
29	//!                                               │
30	//!                              MatVec(hidden, W1) ──► output [DIM]
31	//!                                                        │
32	//!                                                  ReLU(output) ──► result [DIM]
33	//! ```
34	//!
35	//! Build and run with:
36	//!   cargo oxide run async_mlp
37	
38	use cuda_async::device_box::DeviceBox;
39	use cuda_async::device_context::init_device_contexts;
40	use cuda_async::device_operation::{self, DeviceOperation, Zippable, value};
41	use cuda_async::zip;
42	use cuda_core::LaunchConfig;
43	use cuda_core::memory::{malloc_async, memcpy_dtoh_async, memcpy_htod_async, memset_d8_async};
44	use cuda_device::{DisjointSlice, kernel, thread};
45	use cuda_host::cuda_module;
46	use std::future::IntoFuture;
47	use std::mem;
48	use std::sync::Arc;
49	
50	// =============================================================================
51	// KERNELS -- compiled to PTX by rustc-codegen-cuda
52	// =============================================================================
53	
54	/// Naive GEMM: C = alpha * A * B + beta * C
55	/// Each thread computes one element of C. Row-major layout.
56	#[cuda_module]
57	mod kernels {
58	    use super::*;
59	
60	    #[kernel]
61	    pub fn sgemm_naive(
62	        m: u32,
63	        n: u32,
64	        k: u32,
65	        alpha: f32,
66	        a: &[f32],
67	        b: &[f32],
68	        beta: f32,
69	        mut c: DisjointSlice<f32, thread::Runtime2DIndex>,
70	    ) {
71	        let row = thread::index_2d_row();
72	        let col = thread::index_2d_col();
73	
74	        if let Some(c_idx) = unsafe { thread::index_2d_runtime(n as usize) } {
75	            // col < n guaranteed by index_2d_runtime returning Some
76	            if row < m as usize {
77	                let n_sz = n as usize;
78	                let k_sz = k as usize;
79	                let mut sum = 0.0f32;
80	                let mut i = 0usize;
81	                while i < k_sz {
82	                    sum += a[row * k_sz + i] * b[i * n_sz + col];
83	                    i += 1;
84	                }
85	                if let Some(c_elem) = c.get_mut(c_idx) {
86	                    *c_elem = alpha * sum + beta * (*c_elem);
87	                }
88	            }
89	        }
90	    }
91	
92	    /// Naive matrix-vector multiply: out = mat * vec_in
93	    /// Each thread computes one element of the output vector.
94	    #[kernel]
95	    pub fn matvec_naive(
96	        _m: u32,
97	        n: u32,
98	        mat: &[f32],
99	        vec_in: &[f32],
100	        mut vec_out: DisjointSlice<f32>,
101	    ) {
102	        let row = thread::index_1d();
103	        let row_raw = row.get();
104	        if let Some(out_elem) = vec_out.get_mut(row) {
105	            let n_sz = n as usize;
106	            let mut sum = 0.0f32;
107	            let mut j = 0usize;
108	            while j < n_sz {
109	                sum += mat[row_raw * n_sz + j] * vec_in[j];
110	                j += 1;
111	            }
112	            *out_elem = sum;
113	        }
114	    }
115	
116	    /// In-place ReLU: data[i] = max(0, data[i])
117	    #[kernel]
118	    pub fn relu(mut data: DisjointSlice<f32>) {
119	        let idx = thread::index_1d();
120	        if let Some(elem) = data.get_mut(idx) {
121	            let val = *elem;
122	            *elem = if val > 0.0f32 { val } else { 0.0f32 };
123	        }
124	    }
125	}
126	
127	// =============================================================================
128	// DEVICE MEMORY HELPERS -- DeviceOperations for allocation and transfer
129	// =============================================================================
130	
131	/// Allocates device memory and copies host data to it (H2D).
132	/// `ctx` is provided by the scheduler at execution time (not the call site)
133	/// and carries the assigned CUDA stream for this operation.
134	fn h2d(host_data: Vec<f32>) -> impl DeviceOperation<Output = DeviceBox<[f32]>> {
135	    device_operation::with_context(move |ctx| {
136	        let stream = ctx.get_cuda_stream();
137	        let n = host_data.len();
138	        let num_bytes = n * mem::size_of::<f32>();
139	        unsafe {
140	            let dptr = malloc_async(stream.cu_stream(), num_bytes).unwrap();
141	            memcpy_htod_async(dptr, host_data.as_ptr(), num_bytes, stream.cu_stream()).unwrap();
142	            value(DeviceBox::from_raw_parts(dptr, n, ctx.get_device_id()))
143	        }
144	    })
145	}
146	
147	/// Allocates zero-initialized device memory.
148	/// `ctx` is provided by the scheduler at execution time.
149	fn zeros(n: usize) -> impl DeviceOperation<Output = DeviceBox<[f32]>> {
150	    device_operation::with_context(move |ctx| {
151	        let stream = ctx.get_cuda_stream();
152	        let num_bytes = n * mem::size_of::<f32>();
153	        unsafe {
154	            let dptr = malloc_async(stream.cu_stream(), num_bytes).unwrap();
155	            memset_d8_async(dptr, 0, num_bytes, stream.cu_stream()).unwrap();
156	            value(DeviceBox::from_raw_parts(dptr, n, ctx.get_device_id()))
157	        }
158	    })
159	}
160	
161	/// Copies device memory back to host (D2H).
162	/// `ctx` is provided by the scheduler at execution time.
163	fn d2h(dev: DeviceBox<[f32]>) -> impl DeviceOperation<Output = Vec<f32>> {
164	    device_operation::with_context(move |ctx| {
165	        let stream = ctx.get_cuda_stream();
166	        let n = dev.len();
167	        let num_bytes = n * mem::size_of::<f32>();
168	        let mut host = vec![0.0f32; n];
169	        unsafe {
170	            memcpy_dtoh_async(
171	                host.as_mut_ptr(),
172	                dev.cu_deviceptr(),
173	                num_bytes,
174	                stream.cu_stream(),
175	            )
176	            .unwrap();
177	        }
178	        // dev is kept alive in this closure until the stream synchronizes
179	        let _ = &dev;
180	        value(host)
181	    })
182	}
183	
184	// =============================================================================
185	// HOST CODE
186	// =============================================================================
187	
188	const DIM: usize = 64;
189	const BLOCK: u32 = 16;
190	
191	#[tokio::main]
192	async fn main() -> Result<(), Box<dyn std::error::Error>> {
193	    println!("=== Async MLP Pipeline ===\n");
194	
195	    // 1. Initialize the async device context (round-robin pool of 4 streams).
196	    init_device_contexts(0, 1)?;
197	    let module = kernels::load_async(0)?;
198	
199	    // 2. Allocate model weights on device using zip! to compose independent ops.
200	    //    Both allocations are submitted together on the same stream.
201	    println!("Allocating model weights...");
202	    let w0_host: Vec<f32> = (0..DIM * DIM)
203	        .map(|i| ((i % 7) as f32 - 3.0) * 0.01)
204	        .collect();
205	    let w1_host: Vec<f32> = (0..DIM).map(|i| ((i % 5) as f32 - 2.0) * 0.01).collect();
206	
207	    let (w0, w1): (Arc<DeviceBox<[f32]>>, Arc<DeviceBox<[f32]>>) =
208	        zip!(h2d(w0_host).arc(), h2d(w1_host).arc()).await?;
209	    println!(
210	        "  W0: {}x{} on device (Arc refcount={})",
211	        DIM,
212	        DIM,
213	        Arc::strong_count(&w0)
214	    );
215	    println!(
216	        "  W1: {} on device (Arc refcount={})\n",
217	        DIM,
218	        Arc::strong_count(&w1)
219	    );
220	
221	    // 3. Build and launch concurrent forward passes for multiple batches.
222	    //    Each batch is a lazy DeviceOperation graph that gets spawned onto
223	    //    the Tokio runtime. The round-robin scheduling policy distributes
224	    //    work across 4 CUDA streams automatically.
225	    let num_batches = 4;
226	    let mut handles = vec![];
227	
