6	//! Lazy, composable GPU operations and combinator types.
7	//!
8	//! The [`DeviceOperation`] trait is the core abstraction. Each operation
9	//! describes GPU work without binding to a stream. Combinators (`and_then`,
10	//! `zip`, `apply`, `with_context`) compose operations into dataflow graphs
11	//! that remain stream-agnostic until scheduling time.
12	//!
13	//! # Scheduling model
14	//!
15	//! | Method       | What it does                                                      |
16	//! |--------------|-------------------------------------------------------------------|
17	//! | [`schedule`] | Pairs the operation with a stream, returns a [`DeviceFuture`].    |
18	//! | [`sync`]     | Shorthand: schedule + execute + synchronize on the default device.|
19	//! | [`sync_on`]  | Execute and synchronize on a specific stream.                     |
20	//! | [`async_on`] | Execute on a specific stream **without** synchronizing.           |
21	//!
22	//! [`schedule`]: DeviceOperation::schedule
23	//! [`sync`]: DeviceOperation::sync
24	//! [`sync_on`]: DeviceOperation::sync_on
25	//! [`async_on`]: DeviceOperation::async_on
26	//! [`DeviceFuture`]: crate::device_future::DeviceFuture
27	
28	use crate::device_context::with_default_device_policy;
29	use crate::device_future::DeviceFuture;
30	use crate::error::DeviceError;
31	use crate::scheduling_policies::SchedulingPolicy;
32	use cuda_core::{CudaContext, CudaStream};
33	use std::cell::UnsafeCell;
34	use std::future::IntoFuture;
35	use std::marker::PhantomData;
36	use std::sync::Arc;
37	use std::sync::atomic::{AtomicBool, Ordering};
38	
39	/// CUDA device ordinal. Type alias for readability.
40	pub type Device = usize;
41	
42	/// Binds a [`DeviceOperation`] to a concrete CUDA stream and context for
43	/// execution.
44	///
45	/// Created by the scheduling policy when an operation is scheduled. Passed to
46	/// [`DeviceOperation::execute`] to provide the stream and context.
47	#[derive(Debug, Clone)]
48	pub struct ExecutionContext {
49	    /// Device ordinal derived from the CUDA context.
50	    device: Device,
51	    /// Stream on which GPU work will be enqueued.
52	    cuda_stream: Arc<CudaStream>,
53	    /// CUDA context that owns the stream.
54	    cuda_context: Arc<CudaContext>,
55	}
56	
57	impl ExecutionContext {
58	    /// Constructs a context from a stream, deriving the device and CUDA context
59	    /// from the stream's owning context.
60	    pub fn new(cuda_stream: Arc<CudaStream>) -> Self {
61	        let cuda_context = Arc::clone(cuda_stream.context());
62	        let device = cuda_context.ordinal();
63	        Self {
64	            cuda_stream,
65	            cuda_context,
66	            device,
67	        }
68	    }
69	
70	    /// Returns the CUDA stream.
71	    pub fn get_cuda_stream(&self) -> &Arc<CudaStream> {
72	        &self.cuda_stream
73	    }
74	
75	    /// Returns the CUDA context.
76	    pub fn get_cuda_context(&self) -> &Arc<CudaContext> {
