813	/// Schedules via the thread-local default policy.
814	impl<T1: Send + 'static, T2: Send + 'static, DI: DeviceOperation<Output = (T1, T2)>> IntoFuture
815	    for SelectLeft<T1, T2, DI>
816	{
817	    type Output = Result<T1, DeviceError>;
818	    type IntoFuture = DeviceFuture<T1, SelectLeft<T1, T2, DI>>;
819	    fn into_future(self) -> Self::IntoFuture {
820	        match with_default_device_policy(|policy| policy.schedule(self)) {
821	            Ok(Ok(future)) => future,
822	            Ok(Err(e)) | Err(e) => DeviceFuture::failed(e),
823	        }
824	    }
825	}
826	
827	/// Operation that extracts the **right** element of an unzipped pair.
828	///
829	/// Shares a [`Select`] with its corresponding [`SelectLeft`] so the source
830	/// operation is executed at most once.
831	pub struct SelectRight<T1: Send, T2: Send, DI: DeviceOperation<Output = (T1, T2)>> {
832	    /// Shared memoization state.
833	    select: Arc<Select<T1, T2, DI>>,
834	}
835	
836	/// # Safety
837	///
838	/// See [`SelectLeft`]'s `Send` impl.
839	unsafe impl<T1: Send, T2: Send, DI: DeviceOperation<Output = (T1, T2)>> Send
840	    for SelectRight<T1, T2, DI>
841	{
842	}
843	
844	/// Triggers the shared source operation (if not yet done) and returns the
845	/// right element.
846	impl<T1: Send + 'static, T2: Send + 'static, DI: DeviceOperation<Output = (T1, T2)>> DeviceOperation
847	    for SelectRight<T1, T2, DI>
848	{
849	    type Output = T2;
850	
851	    unsafe fn execute(self, context: &ExecutionContext) -> Result<T2, DeviceError> {
852	        unsafe {
853	            self.select.execute(context)?;
854	            Ok(self.select.right())
855	        }
856	    }
857	}
858	
859	/// Schedules via the thread-local default policy.
860	impl<T1: Send + 'static, T2: Send + 'static, DI: DeviceOperation<Output = (T1, T2)>> IntoFuture
861	    for SelectRight<T1, T2, DI>
862	{
863	    type Output = Result<T2, DeviceError>;
864	    type IntoFuture = DeviceFuture<T2, SelectRight<T1, T2, DI>>;
865	    fn into_future(self) -> Self::IntoFuture {
866	        match with_default_device_policy(|policy| policy.schedule(self)) {
867	            Ok(Ok(future)) => future,
868	            Ok(Err(e)) | Err(e) => DeviceFuture::failed(e),
869	        }
870	    }
871	}
872	
873	/// Splits a tuple-producing operation into two independent operations that
874	/// share execution: the source runs at most once, and each selector extracts
875	/// one element.
876	fn _unzip<T1: Send, T2: Send, DI: DeviceOperation<Output = (T1, T2)>>(
877	    input: DI,
878	) -> (SelectLeft<T1, T2, DI>, SelectRight<T1, T2, DI>) {
879	    let select = Select {
880	        computed: AtomicBool::new(false),
881	        input: UnsafeCell::new(Some(input)),
882	        left: UnsafeCell::new(None),
883	        right: UnsafeCell::new(None),
884	    };
885	    let select = Arc::new(select);
886	    let out1 = SelectLeft {
887	        select: Arc::clone(&select),
888	    };
889	    let out2 = SelectRight { select };
890	    (out1, out2)
891	}
892	
893	/// Trait enabling `.unzip()` on any [`DeviceOperation`] that produces a
894	/// 2-tuple.
895	pub trait Unzippable2<T0: Send + 'static, T1: Send + 'static>
896	where
897	    Self: DeviceOperation<Output = (T0, T1)>,
898	{
899	    /// Splits this operation into two independent operations, one for each
900	    /// tuple element. The source executes at most once.
901	    fn unzip(
902	        self,
903	    ) -> (
904	        impl DeviceOperation<Output = T0>,
905	        impl DeviceOperation<Output = T1>,
906	    ) {
907	        _unzip(self)
908	    }
909	}
910	
911	/// Blanket impl: any operation producing `(T0, T1)` is unzippable.
912	impl<T0: Send + 'static, T1: Send + 'static, DI: DeviceOperation<Output = (T0, T1)>>
913	    Unzippable2<T0, T1> for DI
914	{
915	}
916	
917	/// Splits a tuple-producing [`DeviceOperation`] into per-element operations.
918	///
919	/// ```ignore
920	/// let (left, right) = unzip!(pair_op);
921	/// ```
922	#[macro_export]
923	macro_rules! unzip {
924	    ($arg0:expr) => {
925	        $arg0.unzip()
926	    };
927	}
928	pub use unzip;
929	
930	#[cfg(test)]
931	mod tests {
932	    use super::*;
933	
934	    #[test]
935	    fn finish_sync_returns_operation_result_after_successful_synchronize() {
936	        let result = finish_sync::<u32>(Ok(7), Ok(()));
937	
938	        assert_eq!(result, Ok(7));
939	    }
940	
941	    #[test]
942	    fn finish_sync_preserves_operation_error_after_successful_synchronize() {
943	        let operation_error = DeviceError::Launch("launch failed".to_string());
944	        let result = finish_sync::<u32>(Err(operation_error.clone()), Ok(()));
945	
946	        assert_eq!(result, Err(operation_error));
947	    }
948	
949	    #[test]
950	    fn finish_sync_propagates_synchronize_error_instead_of_panicking() {
951	        let driver_error =
952	            cuda_core::DriverError(cuda_bindings::cudaError_enum_CUDA_ERROR_INVALID_VALUE);
953	        let result = finish_sync::<u32>(Ok(7), Err(driver_error));
954	
955	        assert_eq!(result, Err(DeviceError::Driver(driver_error)));
956	    }
957	
958	    #[test]
959	    fn finish_sync_preserves_operation_error_when_synchronize_also_fails() {
960	        let operation_error = DeviceError::Launch("launch failed".to_string());
961	        let driver_error =
962	            cuda_core::DriverError(cuda_bindings::cudaError_enum_CUDA_ERROR_INVALID_VALUE);
963	        let result = finish_sync::<u32>(Err(operation_error.clone()), Err(driver_error));
964	
965	        assert_eq!(result, Err(operation_error));
966	    }
967	}
