38	/// Lifecycle state of a [`DeviceFuture`].
39	#[derive(Debug, Default, Eq, PartialEq, Copy, Clone)]
40	pub enum DeviceFutureState {
41	    /// The future was constructed in a failed state (e.g. scheduling error).
42	    Failed,
43	    /// Initial state: the operation has not yet been submitted to the GPU.
44	    #[default]
45	    Idle,
46	    /// The operation has been submitted; waiting for the stream callback.
47	    Executing,
48	    /// The result has been produced. Polling again will panic.
49	    Complete,
50	}
51	
52	/// Shared state between a [`DeviceFuture`] and its `cuLaunchHostFunc` callback.
53	///
54	/// The callback sets `complete` and wakes the stored waker, allowing the
55	/// executor to re-poll the future without busy-waiting.
56	#[derive(Debug, Default)]
57	pub struct StreamCallbackState {
58	    /// Waker registered by the executor during [`Future::poll`].
59	    pub(crate) waker: AtomicWaker,
60	    /// Set to `true` by the host callback when the GPU reaches the callback
61	    /// point in the stream.
62	    pub(crate) complete: AtomicBool,
63	}
64	
65	impl StreamCallbackState {
66	    /// Creates a new callback state with no registered waker and
67	    /// `complete = false`.
68	    pub fn new() -> Self {
69	        Self::default()
70	    }
71	
72	    /// Marks the stream callback as complete and wakes the associated future.
73	    ///
74	    /// Called from the `cuLaunchHostFunc` host-side callback.
75	    pub fn signal(&self) {
76	        self.complete.store(true, Ordering::Relaxed);
77	        self.waker.wake();
78	    }
79	}
