95	/// [`reclaim`]: crate::reclaim
96	///
97	/// [`SchedulingPolicy::schedule`]: crate::scheduling_policies::SchedulingPolicy::schedule
98	/// [`IntoFuture`]: std::future::IntoFuture
99	#[derive(Debug)]
100	pub struct DeviceFuture<T: Send + 'static, DO: DeviceOperation<Output = T>> {
101	    /// The operation to execute. Consumed on first poll.
102	    pub(crate) device_operation: Option<DO>,
103	    /// Stream and context for execution. Set by the scheduling policy.
104	    pub(crate) execution_context: Option<ExecutionContext>,
105	    /// Holds the result between execution and final poll resolution.
106	    pub(crate) result: Option<T>,
107	    /// Holds an error when the future is in the `Failed` state.
108	    pub(crate) error: Option<DeviceError>,
109	    /// Current lifecycle state.
110	    pub(crate) state: DeviceFutureState,
111	    /// Shared state with the `cuLaunchHostFunc` callback.
112	    pub(crate) callback_state: Option<Arc<StreamCallbackState>>,
113	}
