115	impl<T: Send + 'static, DO: DeviceOperation<Output = T>> DeviceFuture<T, DO> {
116	    /// Creates an idle future with no operation or context attached.
117	    pub fn new() -> Self {
118	        Self::default()
119	    }
120	
121	    /// Creates a future that will immediately yield `Err(error)` on first poll.
122	    pub fn failed(error: DeviceError) -> Self {
123	        Self {
124	            execution_context: None,
125	            device_operation: None,
126	            state: DeviceFutureState::Failed,
127	            callback_state: None,
128	            result: None,
129	            error: Some(error),
