134	    /// when the GPU reaches this point in the stream.
135	    ///
136	    /// # Safety
137	    ///
138	    /// The execution context must hold a valid, non-destroyed CUDA stream.
139	    unsafe fn register_callback(
140	        &self,
141	        waker_state: Arc<StreamCallbackState>,
142	    ) -> Result<(), DeviceError> {
143	        let ctx = self.execution_context.as_ref().ok_or_else(|| {
144	            DeviceError::Internal("Cannot execute future without an execution context.".to_string())
145	        })?;
146	        ctx.get_cuda_stream().launch_host_function(move || {
147	            waker_state.signal();
148	        })?;
149	        Ok(())
150	    }
