152	    /// Takes the stored operation, executes it on the bound stream, and stashes
153	    /// the result. Called exactly once during the `Idle -> Executing` transition.
154	    fn execute(&mut self) -> Result<(), DeviceError> {
155	        let ctx = self.execution_context.as_ref().ok_or_else(|| {
156	            DeviceError::Internal("Cannot execute future without an execution context.".to_string())
157	        })?;
158	        let operation = self
159	            .device_operation
160	            .take()
161	            .ok_or_else(|| DeviceError::Internal("No operation has been set.".to_string()))?;
