290	pub fn load_module_from_ptx(
291	    ptx_src: &str,
292	    device_id: usize,
293	) -> Result<Arc<CudaModule>, DeviceError> {
294	    with_cuda_context(device_id, |cuda_ctx| {
295	        let module = cuda_ctx.load_module_from_ptx_src(ptx_src)?;
296	        Ok(module)
297	    })?
298	}
