300	/// Inserts a compiled function into the per-device kernel cache.
301	///
302	/// The function is keyed by the hash of `func_key`. Returns an error if a
303	/// different function was already registered under the same key (hash
304	/// collision).
305	pub fn insert_cuda_function(
306	    device_id: usize,
307	    func_key: &impl FunctionKey,
308	    value: (Arc<CudaModule>, Arc<CudaFunction>),
309	) -> Result<(), DeviceError> {
310	    with_global_device_context_mut(device_id, |dc| {
311	        let key = func_key.get_hash_string();
312	        let res = dc.functions.insert(key, value);
313	        device_assert(device_id, res.is_none(), "Unexpected cache key collision.")
314	    })?
315	}
