317	/// Retrieves a compiled [`CudaFunction`] from the per-device kernel cache.
318	///
319	/// Returns an error if no function has been registered under `func_key`.
320	pub fn get_cuda_function(
321	    device_id: usize,
322	    func_key: &impl FunctionKey,
323	) -> Result<Arc<CudaFunction>, DeviceError> {
324	    with_global_device_context(device_id, |dc| {
325	        let key = func_key.get_hash_string();
326	        let (_module, function) = dc
327	            .functions
328	            .get(&key)
329	            .ok_or_else(|| device_error(device_id, "Failed to get cuda function."))?;
330	        Ok(Arc::clone(function))
331	    })?
332	}
333	
334	#[cfg(test)]
335	mod tests {
336	    use super::*;
337	
338	    fn assert_duplicate_init_error(result: Result<(), DeviceError>) {
339	        assert!(matches!(
340	            result,
341	            Err(DeviceError::Context {
342	                device_id: 0,
343	                message,
344	            }) if message == "Context already initialized."
345	        ));
346	    }
