348	    #[test]
349	    fn duplicate_init_preserves_existing_device_contexts() {
350	        std::thread::spawn(|| {
351	            init_device_contexts(0, 1).expect("initial context initialization should succeed");
352	
353	            assert_duplicate_init_error(init_device_contexts(0, 1));
354	            assert_duplicate_init_error(init_device_contexts(0, 1));
355	        })
356	        .join()
357	        .expect("test thread should not panic");
358	    }
359	}
